            Assert.Equal("1 in²/in", new AreaPerLength(1, AreaPerLengthUnit.SquareInchPerInch).ToString(swedishCulture));
            Assert.Equal("1 m²/m", new AreaPerLength(1, AreaPerLengthUnit.SquareMeterPerMeter).ToString(swedishCulture));
            Assert.Equal("1 mm²/m", new AreaPerLength(1, AreaPerLengthUnit.SquareMillimeterPerMeter).ToString(swedishCulture));
        }

